# NL DHA.  Den Helder - Amsterdam Centraal
#
let da = path("d3.nl.dha");

with detail = 4,
     railway = :first :cat:dc15 :pax
{
    with link = "point.nl.Den-Helder", railway = :station {
        track(da[:den.f, :den + 200m]);
        marker(:bottom :de.bf, da[:den.f]);
        label(da[:den.f - 1sh] + (0dt, -0.3dt),
            hbox(:center:bottom :bold, "Den Helder")
        );

        marker(:left :ref, da[:den] << 0.5mt);
        marker(:right :ref, da[:den] >> 0.5mt);
        label(da[:den] << 0.5mt << 2dt,
            hbox(:left:middle :xsmall, "DHA: 0,814")
        );
    }

    with link = "line.nl.DHA" {
        track(da[:den + 199m, :dez - 0.49sw]);
    }

    with link = "point.nl.Den-Helder-Zuid", railway = :station {
        track(da[:dez - 0.5sw, :dez + 0.5sw]);
        marker(:left :de.bf, da[:dez] << 0.5mt);
        station(:right, da[:dez] << 0.5mt << 1.sh + (1.8dt, 1dt),
            "Den Helder Zuid", "DHA: 3,363"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:dez + 0.49sw, :dez + 1.51km]);
        line_label(:right:e, da[:dez + 1.5km] >> 0.5mt, (0dt, 0.1dt), "DHA");
        track(da[:dez + 1.49km, :koe - 0.49sw]);
    }

    with link = "point.nl.Koegras", railway = :station {
        track(da[:koe - 0.5sw, :koe + 0.5sw]);
        marker(:right :de.hp :removed, da[:koe] >> 0.5mt);
        station(:bottom :removed, da[:koe] >> 0.5mt >> 1sh + (-2dt, 0.8dt),
            "Koegras", "DHA: 7,1"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:koe + 0.49sw, :bre - 0.49sw]);
    }

    with link = "point.nl.Breezand", railway = :station {
        track(da[:bre - 0.5sw, :bre + 0.5sw]);
