    }

    with link = "line.nl.DHA" {
        track(da[:bre + 0.49sw, :ann - 0.49sw]);
    }

    with link = "point.nl.Anna-Paulowna", railway = :station {
        track(da[:ann - 0.5sw, :ann + 0.5sw]);
