    with link = "point.nl.Oudesluis", railway = :station {
        track(da[:osl - 0.5sw, :osl + 0.5sw]);
        marker(:right :de.hp :removed, da[:osl] >> 0.5mt);
        station(:left :removed, da[:osl] >> 0.5mt >> 1sh + (-1.5dt, 1dt),
            "Oudesluis", "DHA: 16,0"
        );
    }

    with link = "line.nl.DHA" {
        track(
                da[:osl + 0.49sw, :sag - 2.7km]
            ..  da[:sag - 2.5km, :sag - 1.1km] << 0.5mo
            ..  da[:sag - 0.9km, :sag - 299m] >> 0.5mo
