                span(:former, "Koog Bloemwijk"),
                "Koog aan de Zaan"
            ),
            "DHA: 68,816"
        );
    }

    with link = "line.nl.DHA" {
        with layer = -1 track(:double, da[:kog + 0.5sw, :zaa.ad]);
    }

    with link = "point.nl.Zaandam", railway = :station {
        let ze = path("d3.nl.zeh");
        let zs = path("d3.nl.zsg");

        # Sp. PP - 401 (NL ZEH up)
        track(
                ze[:zaa.ae, :zaa.ae - 0.1dl] << 0.5mo
            ..  zs[:zaa.ye, :zaa + 420m - 1dl] << 1.5mo
            --  zs[:zaa + 420m, :zaa + 421m] << 0.5mo
        );

        # Sp. 421 - 402 (NL DHA dn - NL ZSG dn)
        with layer = -1 track(da[:zaa.ad - 1mo, :zaa.ye] << 0.5mo);
        track(zs[:zaa.ye, :zaa.fs] << 0.5mo);

        # Sp. 422 - 403 (NL DHA up - NL ZSG ctr)
        with layer = -1 track(da[:zaa.ad - 1mo, :zaa.ye] >> 0.5mo);
        track(zs[:zaa.ye, :zaa.fs] >> 0.5mo);

        # Sp. PC - 404 (NL ZEH dn - NL ZSG up)
        track(:casing,
                ze[:zaa.ae, :zaa.ae - 0.1dl] >> 0.5mo
            ..  zs[:zaa.ye, :zaa.fs] >> 1.5mo
        );

        # Sp. 423 - 405
        track(
                da[:zaa.ad + 2.9dl, :zaa.ad + 3dl]>> 0.5mo
            --  da[:zaa.ad + 4dl, :zaa.ad + 4.1dl] >> 1.5mo
            ..  zs[:zaa.ye, :zaa + 140m + 1dl] >> 2.5mo
            --  zs[:zaa + 140m + 2dl, :zaa + 140m + 2.1dl] >> 1.5mo
        );

        track(:double :removed, da[:zaa, :zaa + 480m]);


        marker(:left :de.bf, zs[:zaa] << 1.5mo << 0.5mt);
        label(zs[:zaa] << 1.5mo << 0.5mt << 1.4sh + (0.8dt, 1.2dt),
            vbox(:left:base,
                hbox(:center:top :xsmall,
                    vbox(:right:top, "DHA: ", "[ZEH: ", "[ZSG: "),
                    vbox(:sep:top,
                        hbox(:sep:base, "71,", anchor(), "174"),
                        hbox(:sep:base, "−0,", anchor(), "270]"),
                        hbox(:sep:base, "171,", anchor(), "174]")
                    )
                ),
                span(:bold, "Zaandam")
            )
        );
    }
