with detail = 4,
     railway = :first :cat:dc15 :nopax
{
    with link = "point.nl.Amsterdam-Lijnwerkplaats-Noord",
    railway = :station {
        track(da[:lin - 50m, :lin] << 0.5mo);
        track(
                da[:lin - 0.1dl, :lin] << 0.5mo
            ..  da[:lin + 229m, :lin + 230m] >> 0.5mo
        );

        track(da[:lin - 50m, :lin] >> 0.5mo);
        track(da[:lin, :lin + 230m] >> 0.5mo);

        marker(:left :de.abzw, da[:lin] << 0.5mo << 0.5mt);
        station(:right, da[:lin + 0.5sw] << 0.5mo << 0.5mt << 1.2sh,
            span(:small, "A. Lijnwerkplaats Noord"),
            "DHA: 77,350"
        );
    }

    with link = "line.nl.DHA" {
        track(:ror, da[:lin + 230m, :sin.yr] >> 0.5mo);
    }

    # point.nl.Amsterdam-Transformatorweg  nl.ASR

    with link = "line.nl.DHA" {
        track(:ror,
                da[:tra, :tra + 0.1dl] >> 0.5mo
            ..  da[:sin.yz, :sin.yz + 0.1dl] << 4.5mo
        );
    }
}

with detail = 4,
     railway = :first :cat:dc15 :pax
{
    with link = "point.nl.Singelgracht", railway = :station {
        let zs = path("d3.nl.zsg");

        # Lijnwerkplaats
        track(:nopax,
                da[:sin.yz, :sin - 350m - 1.4dl] << 4.5mo
            ..  da[:sin, :sin + 0.1dl] << 2.5mo
        );

        # Spoor SN
        track(
                da[:sin.yz, :sin - 350m - 1.4dl] << 3.5mo
            ..  da[:sin - 1.4dl, :sin - 1.3dl] << 2.5mo
        );

        # Spoor SR
        with layer = 1 track(:casing,
                zs[:obr + 1.9dl, :obr + 2dl] << 0.5mo
            ..  da[:sin.yz, :sin.yz + 0.1dl] << 2.5mo
        );
        track(da[:sin.yz, :sin + 1dl] << 2.5mo);

        # Spoor SS
        with layer = 1 track(:casing,
                zs[:obr + 1.9dl, :obr + 2dl] >> 0.5mo
            ..  da[:sin.yz, :sin.yz + 0.1dl] << 1.5mo
        );
        track(
                da[:sin.yz, :sin - 350m - 1.4dl] << 1.5mo
            ..  da[:sin - 1.4dl, :sin - 1.3dl] << 1.5mo
        );

        # Sporen SO/SP
        track(:double,
                da[:sin.yz, :sin - 350m - 1.4dl]
            ..  da[:sin - 1.4dl, :sin + 1dl] << 1mo
        );

        # Spoor ST
        with layer = 1 track(:casing,
                zs[:obr + 1.9dl, :obr + 2dl] >> 1.75mo
            ..  da[:sin.yz, :sin.yz + 0.1dl] >> 1.5mo
        );
        track(
                da[:sin.yz, :sin - 350m - 1.4dl] >> 1.5mo
            ..  da[:sin - 1.4dl, :sin - 1.3dl] << 0.5mo
        );

        # Spoor SU
        with layer = 1 track(:casing,
                zs[:obr + 1.9dl, :obr + 2dl] >> 2.75mo
            ..  da[:sin.yz, :sin.yz + 0.1dl] >> 2.5mo
        );
        track(
                da[:sin.yz, :sin - 350m - 0.7dl] >> 2.5mo
            ..  da[:sin - 0.7dl, :sin + 1dl] >> 0.5mo
        );

        # Spoor SQ
        track(
                da[:sin.yz, :sin - 350m - 0.7dl] >> 3.5mo
            ..  da[:sin - 0.7dl, :sin + 1dl] >> 0.5mo
        );

        # Sporen SV/SW
        track(:double,
                zs[:obr + 1.9dl, :obr + 2dl] >> 4.5mo
            ..  da[:sin.yz, :sin - 350m] >> 5mo
            ..  da[:sin, :sin + 1dl] >> 2mo
        );

        marker(:left :de.abzw, da[:sin] << 2.5mo << 0.5mt);
        label(da[:sin] << 2.5mo << 0.5mt << 1.2sh,
            hbox(:left:base,
                vbox(:center:base,
                    hbox(:center:bottom :xsmall,
                        vbox(:right:bottom,
                            "DHA: ", "[ASR: ", "[ZSG: ", "[ARD: "
                        ),
                        vbox(:sep:bottom,
                            hbox(:sep:base, "79,", anchor(), "180"),
                            hbox(:sep:base, "48,", anchor(), "775]"),
                            hbox(:sep:base, "181,", anchor(), "600]"),
                            hbox(:sep:base, "−0,", anchor(), "023]")
                        )
                    ),
                    span(:small :bold, "Singelgracht aansl.")
                )
            )
        );
    }

    with link = "line.nl.DHA" {
        # Spoor SF
        track(:dn:rdn, da[:sin + 1dl, :sib + 1dl] << 2.5mo);

        # Sporen SE/SD
        track(:double :ldn:rup,
                da[:sin + 1dl, :sib + 1dl] << 1mo
        );

        # Spoor SC
        track(:up:lup:ror, da[:sin + 1dl, :sib + 1dl] >> 0.5mo);

        # Sporen SB/SA
        track(:double :lor, da[:sin + 1dl, :sib + 1dl] >> 2mo);
    }

    with link = "point.nl.Singelgrachtbrug" {
        marker(:left :de.dkst, da[:sib + 1dl] << 2.5mo << 0.5mt);
        station(:right, da[:sib + 1dl + 0.4sw] << 2.5mo << 0.5mt << 1sh,
            span(:small, "Singelgrachtbrug"), "DHA: 79,375"
        );
    }

    with link = "line.nl.DHA" {
        # Spoor SF
        track(:dn:rdn, da[:sib + 1dl, :ams.a] << 2.5mo);

        # Sporen SE/SD
        track(:double :ldn:rup, da[:sib + 1dl, :ams.a] << 1mo);

        # Spoor SC
        track(:up:lup:ror, da[:sib + 1dl, :ams.a] >> 0.5mo);

        # Sporen SB/SA
        track(:double :lor, da[:sib + 1dl, :ams.a] >> 2mo);
    }

    with link = "point.nl.Amsterdam-Centraal", railway = :station {
        # NL DHA - NL ADC
        track(da[:ams.a, :ams + 300m] << 2.5mo);
        track(:nopax, da[:ams + 300m, :ams.f] << 2.5mo);

        # NL DHA - NL ADC
        track(da[:ams.a, :ams + 300m] << 1.5mo);
        track(:nopax, da[:ams + 300m, :ams.f] << 1.5mo);

        # NL DHA - NL ADC
        track(da[:ams.a, :ams.f] << 0.5mo);

        # NL DHA - NL ADC
        track(da[:ams.a, :ams.f] >> 0.5mo);

        # NL DHA (Haarlemse sporen) - NL ACA
        track(:double, da[:ams.a, :ams.f] >> 2mo);

        marker(:right :de.bf, da[:ams] >> 2.5mo >> 0.5mt);
        station(:left, da[:ams - 1.5sw] >> 2.5mo >> 1.5mt,
            hbox(:right:top :bold, "Amsterdam Centraal"),
            hbox(:center:top,
                vbox(:right:top, "DHA: ", "[ADZ: ", "[ACA: "),
                vbox(:sep:top,
                    hbox(:sep:base, "80,", anchor(), "809"),
                    hbox(:sep:base, "−0,", anchor(), "022]"),
                    hbox(:sep:base, "99,", anchor(), "978]")
                )
            )
        );
    }
}

